#include <stdio.h>
#include <stdlib.h>

int main(void) {
    size_t count;
    if (scanf("%zu", &count) != 1 || count == 0 || count > 100) return 1;
    int *values = malloc(count * sizeof *values);
    if (values == NULL) return 1;
    long long sum = 0;
    for (size_t i = 0; i < count; ++i) {
        if (scanf("%d", &values[i]) != 1) { free(values); return 1; }
        sum += values[i];
    }
    printf("%lld\n", sum);
    free(values);
    return 0;
}
